<section class="admin-page-head"><div><span class="eyebrow">Operations</span><h1>Store settings</h1><p>Turn services on and off without changing website code.</p></div></section><form method="post" class="settings-layout"><?= csrf_field() ?><div class="settings-main"><section class="admin-panel settings-section"><div><span class="step-label">Store status</span><h2>Availability</h2></div><div class="toggle-grid"><?php foreach(['ordering_enabled'=>'Online ordering','pickup_enabled'=>'Pickup','delivery_enabled'=>'Delivery','same_day_enabled'=>'Same-day orders','scheduled_enabled'=>'Scheduled orders','guest_checkout_enabled'=>'Guest checkout','registration_enabled'=>'Customer registration','manual_confirmation'=>'Owner confirmation'] as $key=>$label): ?><label class="toggle-row"><span><strong><?= e($label) ?></strong><small>Enable or pause this feature.</small></span><input type="checkbox" name="<?= e($key) ?>" value="1" <?= setting($key)?'checked':'' ?>><i></i></label><?php endforeach; ?></div></section><section class="admin-panel settings-section"><div><span class="step-label">Business details</span><h2>Store information</h2></div><div class="form-grid"><label>Store name<input name="store_name" value="<?= e(setting('store_name')) ?>"></label><label>Status<select name="store_status"><option value="open" <?= setting('store_status')==='open'?'selected':'' ?>>Open</option><option value="paused" <?= setting('store_status')==='paused'?'selected':'' ?>>Paused</option><option value="closed" <?= setting('store_status')==='closed'?'selected':'' ?>>Closed</option></select></label><label>Phone<input name="store_phone" value="<?= e(setting('store_phone')) ?>"></label><label>Email<input type="email" name="store_email" value="<?= e(setting('store_email')) ?>"></label><label class="full">Tagline<input name="store_tagline" value="<?= e(setting('store_tagline')) ?>"></label><label class="full">Announcement<input name="announcement" value="<?= e(setting('announcement')) ?>"></label><label>Hours<input name="hours" value="<?= e(setting('hours')) ?>"></label><label>License number<input name="license_number" value="<?= e(setting('license_number')) ?>"></label><label class="full">Required warning<textarea name="required_warning" rows="3"><?= e(setting('required_warning')) ?></textarea></label></div></section><section class="admin-panel settings-section"><div><span class="step-label">Fulfillment</span><h2>Locations, areas and minimums</h2></div><div class="form-grid"><label class="full">Pickup address<input name="pickup_address" value="<?= e(setting('pickup_address')) ?>" placeholder="Hidden until pickup is approved"></label><label>Delivery areas<input name="service_areas" value="<?= e(setting('service_areas')) ?>"></label><label>Extended areas<input name="extended_areas" value="<?= e(setting('extended_areas')) ?>"></label><label>Pickup minimum ($)<input type="number" step="0.01" name="pickup_minimum_cents" value="<?= number_format((int)setting('pickup_minimum_cents')/100,2,'.','') ?>"></label><label>Delivery minimum ($)<input type="number" step="0.01" name="delivery_minimum_cents" value="<?= number_format((int)setting('delivery_minimum_cents')/100,2,'.','') ?>"></label><label>Extended-area minimum ($)<input type="number" step="0.01" name="extended_delivery_minimum_cents" value="<?= number_format((int)setting('extended_delivery_minimum_cents')/100,2,'.','') ?>"></label><label>Delivery fee ($)<input type="number" step="0.01" name="delivery_fee_cents" value="<?= number_format((int)setting('delivery_fee_cents')/100,2,'.','') ?>"></label></div></section><section class="admin-panel settings-section"><div><span class="step-label">Payments</span><h2>Allowed methods</h2><p>Approved online payment remains unavailable until a provider adapter is installed and tested.</p></div><div class="toggle-grid"><?php foreach(['pay_at_pickup_enabled'=>'Pay at pickup','manual_prepaid_enabled'=>'Prepaid arrangement'] as $key=>$label): ?><label class="toggle-row"><span><strong><?= e($label) ?></strong><small>Control availability at checkout.</small></span><input type="checkbox" name="<?= e($key) ?>" value="1" <?= setting($key)?'checked':'' ?>><i></i></label><?php endforeach; ?></div><div class="provider-locked"><i data-lucide="lock-keyhole"></i><span><strong>Online card or bank payment</strong><small>Requires a licensed, approved cannabis payment provider.</small></span></div></section></div><aside class="admin-panel settings-save"><h2>Save settings</h2><p>Changes affect checkout immediately. Existing orders keep their original details.</p><button class="button button-primary button-wide" type="submit">Save all settings<i data-lucide="save"></i></button><a class="button button-secondary button-wide" href="<?= url('') ?>">Preview storefront</a></aside></form>
